  CONSTRAINT `fk_courses_semester` FOREIGN KEY (`semester_id`) REFERENCES `semesters` (`id`) ON DELETE RESTRICT ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=6919 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
