--
-- Table structure for table `evaluation_submissions`
--

DROP TABLE IF EXISTS `evaluation_submissions`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `evaluation_submissions` (
  `id` int NOT NULL AUTO_INCREMENT,
  `student_id` int NOT NULL,
  `lecturer_id` int NOT NULL,
  `course_id` int NOT NULL,
  `semester_id` int NOT NULL,
  `academic_year` varchar(20) NOT NULL,
  `type` enum('theory','practical') NOT NULL,
  `overall_grade` decimal(5,2) DEFAULT NULL,
  `comment_text` text,
  `submitted_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uq_evaluation_submissions_once` (`student_id`,`lecturer_id`,`course_id`,`semester_id`,`type`),
  UNIQUE KEY `uq_evaluation_submissions_once_year` (`student_id`,`lecturer_id`,`course_id`,`semester_id`,`academic_year`,`type`),
  KEY `idx_eval_submissions_lecturer_id` (`lecturer_id`),
  KEY `idx_eval_submissions_course_id` (`course_id`),
  KEY `idx_eval_submissions_semester_id` (`semester_id`),
  KEY `idx_eval_submissions_submitted_at` (`submitted_at`),
  KEY `idx_eval_submissions_type` (`type`),
  CONSTRAINT `fk_evaluation_submissions_course` FOREIGN KEY (`course_id`) REFERENCES `courses` (`id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `fk_evaluation_submissions_lecturer` FOREIGN KEY (`lecturer_id`) REFERENCES `users` (`id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `fk_evaluation_submissions_semester` FOREIGN KEY (`semester_id`) REFERENCES `semesters` (`id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `fk_evaluation_submissions_student` FOREIGN KEY (`student_id`) REFERENCES `users` (`id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=548 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

