INSERT INTO `evaluation_submissions` VALUES (428,631,10,4441,19,'2025/2026','theory',80.00,'The lecturer explained the concepts clearly and connected them with real-world examples. The lecture slides were useful, but sometimes the pace was a little fast during difficult topics.','2026-07-13 14:27:35'),(429,631,10,4441,19,'2025/2026','practical',100.00,'The practical session was well organized and the demonstrations helped us understand the experiment. More time for individual practice would make the session even better.','2026-07-13 14:27:35'),(430,634,10,4441,19,'2025/2026','theory',60.00,'The lecturer has strong subject knowledge and answers questions patiently. It would be helpful if more revision questions were provided before assessments.','2026-07-13 14:27:35'),(431,634,10,4441,19,'2025/2026','practical',80.00,'The lecturer gave clear safety instructions and guided students during the laboratory work. It would help if equipment and materials were checked earlier to avoid delays.','2026-07-13 14:27:35'),(432,2,10,4441,19,'2025/2026','theory',100.00,'The lectures were organized and the examples made the subject easier to understand. More short class activities would help students stay engaged throughout the session.','2026-07-13 14:27:35'),(433,2,10,4441,19,'2025/2026','practical',60.00,'The procedures were explained clearly before we started and feedback was useful. More examples of common errors would help us improve our practical records.','2026-07-13 14:27:35'),(434,632,10,4441,19,'2025/2026','theory',80.00,'The lecturer communicates well and makes complex ideas approachable. Some topics need a little more time because the final part of the lecture can feel rushed.','2026-07-13 14:27:35'),(435,632,10,4441,19,'2025/2026','practical',100.00,'The practical work helped us develop useful scientific skills. The session would be stronger with a little more time for discussion after completing the activity.','2026-07-13 14:27:35'),(436,631,647,4453,19,'2025/2026','t